from mcp.server import Server
from pathlib import Path

app = Server("file-server")

@app.resource()
def get_config() -> str:
    """Read configuration file"""
    return Path("config.json").read_text()

# OR with custom URI pattern
@app.resource("file://{path}")
def read_file(path: str) -> str:
    """Read any file from disk"""
    return Path(path).read_text()

@app.resource("db://{table}/{id}")
def get_db_record(table: str, id: str) -> str:
    """Read from database"""
    return f"Record {id} from {table}"

@app.resource("log://customer/{customer_id}")
def get_customer_logs(customer_id: str) -> str:
    """Recent logs for customer troubleshooting"""
    return f"Logs for customer {customer_id}: ERROR connection timeout"

@app.resource("db://schema/users")
def get_user_schema() -> str:
    """Database schema for users table"""
    return """
    CREATE TABLE users (
        id INTEGER PRIMARY KEY,
        name TEXT NOT NULL,
        email TEXT UNIQUE
    )
    """

@app.resource("file:///config/api.json")
def get_api_config() -> str:
    """API configuration with endpoints and keys"""
    return '{"api_key": "xxx", "endpoint": "https://api.example.com"}'

@app.resource("image://uploads/{filename}")
def get_image(filename: str) -> bytes:
    """Read image file"""
    with open(f"uploads/{filename}", "rb") as f:
        return f.read()  # Returns bytes, mimeType: "image/jpeg"

