from mcp.server import Server

app = Server("complete-server")

# TOOL: Action with side effects
@app.tool()
def send_email(to: str, subject: str, body: str) -> str:
    """Send an email to recipient"""
    # Actually sends email
    return f"Email sent to {to}"

# RESOURCE: Readable data
@app.resource("log://app")
def get_app_logs() -> str:
    """Recent application logs"""
    return "2024-01-15 INFO Starting...\n2024-01-15 ERROR Failed"

# PROMPT: Reusable template
@app.prompt("email_draft")
def email_draft(topic: str) -> list:
    """Draft an email about a topic"""
    return [
        {"role": "system", "content": "You are a professional writer."},
        {"role": "user", "content": f"Write an email about {topic}"}
    ]
